import azure.functions as func
import json

def main(req: func.HttpRequest) -> func.HttpResponse:
    # Get HTTP method
    method = req.method

    # Create a response object
    response = func.HttpResponse()

    # Handle OPTIONS preflight requests
    if method == 'OPTIONS':
        response.status_code = 200
        response.headers['Access-Control-Allow-Origin'] = '*'
        response.headers['Access-Control-Allow-Methods'] = 'GET, POST, PUT, DELETE, OPTIONS'
        response.headers['Access-Control-Allow-Headers'] = 'Content-Type, X-Requested-With'
        response.headers['Access-Control-Max-Age'] = '86400' # Cache preflight for 24 hours
        return response

    # Handle other HTTP methods (GET, POST, etc.)
    try:
        # Example: Process request body for POST/PUT
        if method in ['POST', 'PUT']:
            req_body = req.get_json()
            message = f"Received {method} request with body: {req_body}"
        else:
            message = f"Received {method} request."

        # Example: Add query parameters to message for GET
        name = req.params.get('name')
        if name:
            message += f" Hello, {name}!"

        # Construct the response body
        response_data = {
            "status": "success",
            "message": message,
            "method": method,
            "headers_received": dict(req.headers)
        }

        response.set_json(json.dumps(response_data))
        response.status_code = 200

    except ValueError:
        response.set_json(json.dumps({
            "status": "error",
            "message": "Invalid JSON body provided."
        }))
        response.status_code = 400
    except Exception as e:
        response.set_json(json.dumps({
            "status": "error",
            "message": f"An unexpected error occurred: {str(e)}"
        }))
        response.status_code = 500

    # Set CORS headers for all successful responses
    response.headers['Access-Control-Allow-Origin'] = '*'
    response.headers['Access-Control-Allow-Methods'] = 'GET, POST, PUT, DELETE, OPTIONS' # Ensure all methods are allowed
    response.headers['Access-Control-Allow-Headers'] = 'Content-Type, X-Requested-With' # Common headers

    return response